-- Insert Source Documents
INSERT INTO public.source_documents (patient_id, episode_id, title, content, document_type, author_id, metadata) VALUES
('02cd41c5-2120-41a6-862f-97004164dba5', (SELECT id FROM public.episodes WHERE patient_id = '02cd41c5-2120-41a6-862f-97004164dba5' LIMIT 1), 'Hospital Discharge Summary', 'Patient admitted with acute stroke. CT scan showed left middle cerebral artery infarct. Patient underwent thrombolytic therapy with good response. Discharge with residual right-sided weakness.', 'medical_record', (SELECT id FROM public.profiles WHERE role = 'nurse' LIMIT 1), '{"source": "General Hospital", "date": "2025-01-14"}'),
('02cd41c5-2120-41a6-862f-97004164dba5', (SELECT id FROM public.episodes WHERE patient_id = '02cd41c5-2120-41a6-862f-97004164dba5' LIMIT 1), 'PT Initial Evaluation', 'Patient presents with right hemiparesis. Strength 3/5 in right upper and lower extremity. Balance impaired, requires assistance for transfers. Recommended intensive PT 3x weekly.', 'assessment_note', (SELECT id FROM public.profiles WHERE discipline = 'physical_therapy' LIMIT 1), '{"therapist": "Sarah Johnson, PT", "date": "2025-01-17"}'),
('8309d3e1-f064-42d4-8b2e-50ce1054f16a', (SELECT id FROM public.episodes WHERE patient_id = '8309d3e1-f064-42d4-8b2e-50ce1054f16a' LIMIT 1), 'Psychiatric Evaluation', 'Patient with history of major depressive disorder, currently stable on medication. Parkinson\'s symptoms well-controlled with current regimen. Continue current medications.', 'medical_record', (SELECT id FROM public.profiles WHERE discipline = 'social_work' LIMIT 1), '{"psychiatrist": "Dr. Michael Chen", "date": "2025-01-19"}'),
('3712e0c0-0ea1-41d8-87fd-39bcaf748799', (SELECT id FROM public.episodes WHERE patient_id = '3712e0c0-0ea1-41d8-87fd-39bcaf748799' LIMIT 1), 'Neurology Consult', 'Parkinson\'s disease stage 2. Tremor predominantly affecting left hand. Gait slightly affected. Recommend continuing current medication with possible adjustment.', 'medical_record', (SELECT id FROM public.profiles WHERE role = 'nurse' LIMIT 1), '{"neurologist": "Dr. Lisa Wang", "date": "2025-01-24"}');

