('02cd41c5-2120-41a6-862f-97004164dba5', (SELECT id FROM public.episodes WHERE patient_id = '02cd41c5-2120-41a6-862f-97004164dba5' LIMIT 1), 'Wound Care Progress', 'Chronic wound on right heel showing improvement with current dressing protocol. Size decreased from 3cm to 2.1cm. No signs of infection. Continue current treatment plan.', 'nursing', 'medium', '{"wound_care", "healing", "progress"}', (SELECT id FROM public.profiles WHERE discipline = 'nursing' LIMIT 1)),
('02cd41c5-2120-41a6-862f-97004164dba5', (SELECT id FROM public.episodes WHERE patient_id = '02cd41c5-2120-41a6-862f-97004164dba5' LIMIT 1), 'Physical Therapy Progress', 'Patient demonstrating good progress with strengthening exercises. Able to perform bed mobility with minimal assistance. Working on sitting balance and transfer training. Family actively participating in learning transfer techniques.', 'physical_therapy', 'normal', '{"progress", "mobility", "transfers", "family_training"}', (SELECT id FROM public.profiles WHERE discipline = 'physical_therapy' LIMIT 1)),

('8309d3e1-f064-42d4-8b2e-50ce1054f16a', (SELECT id FROM public.episodes WHERE patient_id = '8309d3e1-f064-42d4-8b2e-50ce1054f16a' LIMIT 1), 'Depression Monitoring', 'Patient reports improved mood since starting home health services. Spouse notes increased engagement in daily activities. PHQ-9 score improved from 12 to 8. Continue monitoring and support.', 'social_work', 'high', '{"depression", "mood", "improvement", "spouse_support"}', (SELECT id FROM public.profiles WHERE discipline = 'social_work' LIMIT 1)),
('8309d3e1-f064-42d4-8b2e-50ce1054f16a', (SELECT id FROM public.episodes WHERE patient_id = '8309d3e1-f064-42d4-8b2e-50ce1054f16a' LIMIT 1), 'Medication Management', 'Patient demonstrates good understanding of medication regimen. Pill organizer system working well. No adverse effects reported. Tremor well-controlled with current Parkinson\'s medications.', 'nursing', 'normal', '{"medications", "compliance", "tremor", "parkinson"}', (SELECT id FROM public.profiles WHERE discipline = 'nursing' LIMIT 1)),

('3712e0c0-0ea1-41d8-87fd-39bcaf748799', (SELECT id FROM public.episodes WHERE patient_id = '3712e0c0-0ea1-41d8-87fd-39bcaf748799' LIMIT 1), 'Parkinson\'s Management', 'Patient managing Parkinson\'s symptoms well with current medication timing. Family educated on importance of medication schedule. Recommend occupational therapy evaluation for home safety.', 'nursing', 'medium', '{"parkinson", "medications", "timing", "safety"}', (SELECT id FROM public.profiles WHERE discipline = 'nursing' LIMIT 1)),
('3712e0c0-0ea1-41d8-87fd-39bcaf748799', (SELECT id FROM public.episodes WHERE patient_id = '3712e0c0-0ea1-41d8-87fd-39bcaf748799' LIMIT 1), 'Gait Training Progress', 'Patient showing improvement in gait stability. Able to walk 50 feet with walker. Balance exercises progressing well. Recommend continuation of current PT plan with focus on endurance.', 'physical_therapy', 'normal', '{"gait", "balance", "walker", "endurance"}', (SELECT id FROM public.profiles WHERE discipline = 'physical_therapy' LIMIT 1));

